// y = tanh(x * W^T + b)  -- Gemm with transB=1
template<int OutDim, int InDim>
inline void linear(float *out, const float *in,
                   const float *weight, const float *bias)
{
    for (int o = 0; o < OutDim; ++o) {
        float sum = bias[o];
        for (int i = 0; i < InDim; ++i)
            sum += in[i] * weight[o * InDim + i];
        out[o] = sum;
    }
}

template<int N>
inline void tanhActivation(float *x)
{
    for (int i = 0; i < N; ++i)
        x[i] = std::tanh(x[i]);
}

/// Run the policy network: 5 floats in -> 2 logits out.
/// Returns P(flap) via softmax of logit[1].
inline float predict(const std::array<float, kInput> &obs)
{
    float h0[kHidden];
    linear<kHidden, kInput>(h0, obs.data(), kW0, kB0);
    tanhActivation<kHidden>(h0);

    float h1[kHidden];
    linear<kHidden, kHidden>(h1, h0, kW1, kB1);
    tanhActivation<kHidden>(h1);

    float logits[kOutput];
    linear<kOutput, kHidden>(logits, h1, kW2, kB2);

    // Numerically stable softmax for P(flap)
    const float mx = std::max(logits[0], logits[1]);
    const float e0 = std::exp(logits[0] - mx);
    const float e1 = std::exp(logits[1] - mx);
    return e1 / (e0 + e1);
}

